def claim_8():
    """
    Claim: The unstable cathode material LiMnO2 can decompose into products
    that include Li2MnO3, which itself is a stable material with a direct band gap.
    """
    # CLEANUP - BKJ - thermo -> summary.  other fix ups.
    # VALIDATED:MAYBE - BKJ - seems correct - all unstable LiMnO2 materaisl appear to decompose into LiMnO2?

    summaries = mpr.materials.summary.search(formula="LiMnO2", is_stable=False, fields=["material_id", "formula_pretty", "decomposes_to"])

    decomp_product_ids = set()
    for x in summaries:
        if x.decomposes_to is None:
            continue

        for product in x.decomposes_to:
            decomp_product_ids.add(str(product.material_id))

    product_docs = mpr.materials.summary.search(material_ids=decomp_product_ids, fields=["material_id", "formula_pretty", "is_stable", "is_gap_direct"])

    for product in product_docs:
        if product.formula_pretty == 'Li2MnO3':
            return product.is_stable and product.is_gap_direct

    return False


assert (claim_8() == False)
